function reducer(state, action) {
  switch (action.type) {
    case 'answered': return { ...state, answer: action.answer };
    case 'submitted': return { ...state, submitted: true };
    default: return state;
  }
}
const [state, dispatch] = useReducer(reducer, initialState);

